def main():
    s = input()
    n = len(s)
    ans = 0
    while True:
        ok = True
        for i in range(n - 1):
            if s[i] == s[i + 1]:
                ok = False
                break
        if ok:
            break
        s = s[1:-1]
        ans += 1
    print(ans)

if __name__ == "__main__":
    main()

